const { randomUUID } = require('node:crypto');
const errors = require('../../lib/errors');

let tasksStore = {};

function getTasks(projectId) {
  return tasksStore[projectId] || [];
}

function addTask(projectId, task) {
  if (!tasksStore[projectId]) {
    tasksStore[projectId] = [];
  }
  const newTask = { id: randomUUID(), ...task };
  tasksStore[projectId].push(newTask);
  return newTask;
}

function updateTask(projectId, taskId, status) {
  if (!tasksStore[projectId]) {
    return null;
  }
  const task = tasksStore[projectId].find(t => t.id === taskId);
  if (task) {
    task.status = status;
  }
  return task;
}

module.exports = {
  getTasks,
  addTask,
  updateTask
};
